__global__ void fused_matmul(float* A, float* B, float* C, int M, int N, int K) {
    int row_base = (blockIdx.y * blockDim.y + threadIdx.y) * 2;
    int col_base = (blockIdx.x * blockDim.x + threadIdx.x) * 4;
    __shared__ float As[272];
    int sr0 = threadIdx.y * 2;
    int sr1 = sr0 + 1;
    float acc00 = 0.0f;
    float acc01 = 0.0f;
    float acc02 = 0.0f;
    float acc03 = 0.0f;
    float acc10 = 0.0f;
    float acc11 = 0.0f;
    float acc12 = 0.0f;
    float acc13 = 0.0f;
    for (int tile_k = 0; tile_k < K; tile_k += 16) {
        if (threadIdx.x < 16) {
            As[sr0 * 17 + threadIdx.x] = ((row_base + 0 < M && tile_k + threadIdx.x < K) ? (A[(row_base + 0) * K + (tile_k + threadIdx.x)]) : (0.0f));
            As[sr1 * 17 + threadIdx.x] = ((row_base + 1 < M && tile_k + threadIdx.x < K) ? (A[(row_base + 1) * K + (tile_k + threadIdx.x)]) : (0.0f));
        }
        __syncthreads();
        if (col_base + 3 < N) {
            #pragma unroll
            for (int kk = 0; kk < 16; kk++) {
                float a0 = As[sr0 * 17 + kk];
                float a1 = As[sr1 * 17 + kk];
                float4 b4 = *reinterpret_cast<float4*>(&B[(tile_k + kk) * N + col_base]);
                acc00 += a0 * b4.x;
                acc01 += a0 * b4.y;
                acc02 += a0 * b4.z;
                acc03 += a0 * b4.w;
                acc10 += a1 * b4.x;
                acc11 += a1 * b4.y;
                acc12 += a1 * b4.z;
                acc13 += a1 * b4.w;
            }
        }
        __syncthreads();
    }
    if (row_base + 1 < M && col_base + 3 < N) {
        C[(row_base + 0) * N + (col_base + 0)] = acc00;
        C[(row_base + 0) * N + (col_base + 1)] = acc01;
        C[(row_base + 0) * N + (col_base + 2)] = acc02;
        C[(row_base + 0) * N + (col_base + 3)] = acc03;
        C[(row_base + 1) * N + (col_base + 0)] = acc10;
        C[(row_base + 1) * N + (col_base + 1)] = acc11;
        C[(row_base + 1) * N + (col_base + 2)] = acc12;
        C[(row_base + 1) * N + (col_base + 3)] = acc13;
    }
}
